import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Materials = () => {
    const [materials, setMaterials] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [search, setSearch] = useState('');
    const [sort, setSort] = useState('newest');
    const [commentInput, setCommentInput] = useState({});
    const navigate = useNavigate();

    const fetchMaterials = async (q = search, s = sort) => {
        try {
            setLoading(true);
            const res = await axios.get('http://localhost:5000/api/materials', { params: { search: q, sort: s } });
            setMaterials(res.data.data);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to load materials');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchMaterials('', 'newest');
    }, []);

    const getTypeBadge = (type) => {
        const typeLower = type.toLowerCase();
        let badgeClass = 'badge-other';
        if (['pdf', 'ppt', 'docx', 'video'].includes(typeLower)) {
            badgeClass = `badge-${typeLower}`;
        }
        return <span className={`badge ${badgeClass}`}>{type}</span>;
    };

    const reactMaterial = async (id, action) => {
        try {
            const res = await axios.post(`http://localhost:5000/api/materials/${id}/${action}`);
            setMaterials((prev) => prev.map((m) => (
                m._id === id ? { ...m, likes: res.data.likes, dislikes: res.data.dislikes } : m
            )));
        } catch (err) {
            setError(err.response?.data?.message || 'Action failed');
        }
    };

    const commentMaterial = async (id) => {
        const text = (commentInput[id] || '').trim();
        if (!text) return;
        try {
            const res = await axios.post(`http://localhost:5000/api/materials/${id}/comments`, { text });
            setMaterials((prev) => prev.map((m) => (
                m._id === id ? { ...m, comments: res.data.comments } : m
            )));
            setCommentInput((prev) => ({ ...prev, [id]: '' }));
        } catch (err) {
            setError(err.response?.data?.message || 'Comment failed');
        }
    };

    return (
        <div className="container page">
            <div className="page-header">
                <h1>📚 Lecture Materials</h1>
                <button className="btn btn-primary" onClick={() => navigate('/student/materials/upload')}>Upload Material</button>
            </div>
            <div className="card" style={{ marginBottom: 16, display: 'flex', gap: 12, alignItems: 'center', flexWrap: 'wrap' }}>
                <input
                    style={{ flex: 1, minWidth: 220 }}
                    placeholder="Search by title, module, keyword..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                />
                <select value={sort} onChange={(e) => setSort(e.target.value)}>
                    <option value="newest">Newest</option>
                    <option value="likes">Most Liked</option>
                    <option value="module">Module</option>
                </select>
                <button className="btn btn-outline btn-sm" onClick={() => fetchMaterials(search, sort)}>Search / Sort</button>
            </div>

            {error && <div className="alert alert-error">{error}</div>}

            {loading ? (
                <div className="loading">Loading...</div>
            ) : materials.length === 0 ? (
                <div className="empty-state">
                    <p>No materials yet. Be the first to upload!</p>
                </div>
            ) : (
                <div className="card-grid">
                    {materials.map(mat => (
                        <div key={mat._id} className="card" style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                            <div style={{ fontWeight: 'bold', fontSize: '16px' }}>{mat.title}</div>
                            <div style={{ color: 'var(--muted)', fontSize: '13px' }}>{mat.module}</div>
                            <div>{getTypeBadge(mat.type)}</div>
                            <div style={{ fontSize: '13px', color: 'var(--text)' }}>{mat.description || 'No description provided.'}</div>
                            <div style={{ fontSize: '13px', color: 'var(--text)' }}>Uploaded by {mat.studentName}</div>
                            <div style={{ display: 'flex', gap: 8 }}>
                                <button className="btn btn-outline btn-sm" onClick={() => reactMaterial(mat._id, 'like')}>👍 {mat.likes?.length || 0}</button>
                                <button className="btn btn-outline btn-sm" onClick={() => reactMaterial(mat._id, 'dislike')}>👎 {mat.dislikes?.length || 0}</button>
                            </div>
                            <a href={mat.link} target="_blank" rel="noopener noreferrer" className="btn btn-outline btn-sm" style={{ marginTop: 'auto', textDecoration: 'none' }}>
                                🔗 Open Link
                            </a>
                            <div>
                                <textarea
                                    rows="2"
                                    placeholder="Comment..."
                                    value={commentInput[mat._id] || ''}
                                    onChange={(e) => setCommentInput((prev) => ({ ...prev, [mat._id]: e.target.value }))}
                                />
                                <button className="btn btn-sm btn-primary" onClick={() => commentMaterial(mat._id)}>Post</button>
                            </div>
                            <div style={{ maxHeight: 120, overflow: 'auto' }}>
                                {(mat.comments || []).slice(-3).map((c) => (
                                    <div key={c._id} style={{ fontSize: 12, marginTop: 4 }}>
                                        <strong>{c.user?.name || 'User'}:</strong> {c.text}
                                    </div>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default Materials;
